package org.joda.time;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.joda.time.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.joda.time.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.joda.time.Partial;
import org.joda.time.DateTimeFieldType;
import static org.junit.Assert.*;

public class StepDefs {

    private Partial partial;
    private Exception exception;

    @Given("a Partial instance with {string} set to {int} and {string} set to {int}")
    public void a_Partial_instance_with_field1_set_to_value1_and_field2_set_to_value2(String field1, int value1, String field2, int value2) {
        DateTimeFieldType fieldType1 = getDateTimeFieldType(field1);
        DateTimeFieldType fieldType2 = getDateTimeFieldType(field2);
        partial = new Partial(
            new DateTimeFieldType[] {fieldType1, fieldType2},
            new int[] {value1, value2}
        );
    }

    @When("I attempt to create a new Partial by adding {string} with value {int}")
    public void i_attempt_to_create_a_new_partial_by_adding_field_with_value(String field, int value) {
        try {
            DateTimeFieldType fieldType = getDateTimeFieldType(field);
            // Attempt to create a new partial with the duplicate field - this should throw
            partial.with(fieldType, value);
            exception = null;
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("an IllegalArgumentException should be thrown")
    public void an_IllegalArgumentException_should_be_thrown() {
        assertNotNull("Expected IllegalArgumentException to be thrown", exception);
        assertTrue("Exception should be an IllegalArgumentException", 
                   exception instanceof IllegalArgumentException);
    }

    @Then("the exception message should mention {string}")
    public void the_exception_message_should_mention_duplicate(String keyword) {
        assertNotNull("Exception should have been thrown", exception);
        String message = exception.getMessage();
        assertTrue("Exception message should contain '" + keyword + "', but was: " + message,
                   message != null && message.toLowerCase().contains(keyword.toLowerCase()));
    }

    private DateTimeFieldType getDateTimeFieldType(String fieldName) {
        switch (fieldName) {
            case "hourOfDay":
                return DateTimeFieldType.hourOfDay();
            case "minuteOfHour":
                return DateTimeFieldType.minuteOfHour();
            case "clockhourOfDay":
                return DateTimeFieldType.clockhourOfDay();
            default:
                throw new IllegalArgumentException("Unknown field type: " + fieldName);
        }
    }
}

